import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Input,
  Select,
  detectDateRangePreset,
  SearchTextInput,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  dispatchAppToast,
  useCatalogTableBusy,
  useErpListSelection,
} from '@linm-soft-org/linm-web-common-components';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useAppDispatch } from '../../../store/hooks';
import { usePxkListFilterState } from '../../../hooks/usePxkListFilterState';
import { usePxkPermissions } from '../../../hooks/usePxkPermissions';
import { wmsService } from '../../../services/kho/wmsService';
import type { StageIssueDto, VoucherLineDto } from '../../../services/kho/models';
import { VOUCHER_STATUS_OPTIONS } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { pxkNghiepVuLabels } from '../../../constants/pxkNghiepVuPageLabels';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { WmsInlineCreateListShell } from '../../../components/list/WmsInlineCreateListShell';
import { buildPurchasingListToolbar } from '../../../features/mh/purchasingListToolbar';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../../../components/list/VoucherListPagination';
import { ContractSearchField } from '../../../components/search';
import { InlineVoucherMaterialCreatePanel } from '../../../components/form';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'erp-pxk-cong-doan';
const PAGE_ID = 'kho-pxk-cong-doan';
const labels = pxkNghiepVuLabels.congDoan;
const emptyLine = (): VoucherLineDto => ({ materialCode: '', unitCode: '', quantity: 1, unitPrice: 0, amount: 0 });

const PxkCongDoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canCreate, canWrite } = usePxkPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = usePxkListFilterState(LIST_FILTER_SCOPE.pxkCongDoan);

  const [reloadKey, setReloadKey] = useState(0);
  const [showForm, setShowForm] = useState(false);
  const [items, setItems] = useState<StageIssueDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [pageSize, setPageSize] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [voucherDate, setVoucherDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [fromStageId, setFromStageId] = useState('');
  const [toStageId, setToStageId] = useState('');
  const [contractCode, setContractCode] = useState('');
  const [contractCustomerName, setContractCustomerName] = useState('');
  const [lines, setLines] = useState<VoucherLineDto[]>([emptyLine()]);
  const [saving, setSaving] = useState(false);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
  });

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
    selection.clearActiveRow();
  }, [selection]);

  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
    selection.clearActiveRow();
  }, [searchDraft, setSearch, resetPage, selection]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      wmsService.getStageIssues({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        search: search || undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, page, pageSize, search, dispatch, reloadKey]);

  const updateLine = (idx: number, patch: Partial<VoucherLineDto>) => {
    setLines(prev => prev.map((l, i) => (i === idx ? { ...l, ...patch } : l)));
  };

  const handleCreate = async () => {
    if (!fromStageId || !toStageId) {
      dispatchAppToast(dispatch, { message: labels.headerWarning, type: 'warning' });
      return;
    }
    setSaving(true);
    try {
      await wmsService.createStageIssue({
        voucherDate: new Date(voucherDate).toISOString(),
        fromStageId,
        toStageId,
        contractCode: contractCode || undefined,
        lines: lines.filter(l => l.materialCode.trim()),
      });
      dispatchAppToast(dispatch, { message: labels.createSuccess, type: 'success' });
      setShowForm(false);
      setLines([emptyLine()]);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, pxkNghiepVuLabels.saveError),
        type: 'error',
      });
    } finally { setSaving(false); }
  };

  const toolbarActions = useMemo(
    () => buildPurchasingListToolbar({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      onEditConfig: () => setShowSchemaEditor(true),
      canCreate: canCreate && !showForm,
      onCreate: () => setShowForm(true),
    }),
    [refresh, canCreate, showForm],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          applyDateRange(from, to, detectDateRangePreset(from, to) || 'custom');
          resetPage();
        }}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                placeholder={labels.searchPlaceholder}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-status`}>
              <Select
                label="Trạng thái"
                value={status}
                onChange={e => { setStatus(e.target.value); resetPage(); }}
                options={VOUCHER_STATUS_OPTIONS}
                data-testid={`${TEST_ID}-filter-status`}
              />
            </div>
          </>
        )}
      />
    ),
    [
      fromDate,
      toDate,
      searchDraft,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
      showTableLoading,
    ],
  );

  const createPanel = showForm && canWrite ? (
    <InlineVoucherMaterialCreatePanel
      testId={`${TEST_ID}-create-form`}
      headerFields={(
        <div className={df.row4}>
          <div className={df.field}><label className={df.label}>Ngày</label><Input type="date" value={voucherDate} onChange={e => setVoucherDate(e.target.value)} size="small" /></div>
          <div className={df.field}><label className={df.label}>CD nguồn</label><Input value={fromStageId} onChange={e => setFromStageId(e.target.value)} size="small" /></div>
          <div className={df.field}><label className={df.label}>CD đích</label><Input value={toStageId} onChange={e => setToStageId(e.target.value)} size="small" /></div>
          <div className={df.field}>
            <label className={df.label}>Số tham chiếu (HĐ)</label>
            <ContractSearchField
              contractCode={contractCode}
              customerName={contractCustomerName}
              onSelect={(code, name) => { setContractCode(code); setContractCustomerName(name); }}
              onClear={() => { setContractCode(''); setContractCustomerName(''); }}
            />
          </div>
        </div>
      )}
      lines={lines}
      setLines={setLines}
      updateLine={updateLine}
      emptyLine={emptyLine}
      onSave={handleCreate}
      onClose={() => setShowForm(false)}
      saving={saving}
    />
  ) : null;

  return (
    <WmsInlineCreateListShell
      testIdPrefix={TEST_ID}
      pageId={PAGE_ID}
      title={labels.title}
      titleIconClass="fas fa-layer-group"
      listSubtitle={labels.listSubtitle}
      catalogKind={LIST_UI_SCHEMA_KIND.stageIssue}
      emptyLabel={labels.empty}
      items={items}
      page={page}
      pageSize={pageSize}
      showTableLoading={showTableLoading}
      selection={selection}
      toolbarActions={toolbarActions}
      filters={listFilters}
      createPanel={createPanel}
      footer={(
        <VoucherListPagination
          testIdPrefix={TEST_ID}
          page={page}
          totalCount={totalCount}
          pageSize={pageSize}
          onPageChange={p => { setPage(p); selection.clearActiveRow(); }}
          onPageSizeChange={size => {
            setPageSize(size as ListPageSize);
            setPage(1);
            selection.clearActiveRow();
          }}
        />
      )}
      modals={(
        <ListUiSchemaEditorModal
          testIdPrefix={TEST_ID}
          catalogKind={LIST_UI_SCHEMA_KIND.stageIssue}
          isOpen={showSchemaEditor}
          onClose={() => setShowSchemaEditor(false)}
          title="Cấu hình hiển thị danh sách"
          onSaved={() => { setReloadKey(k => k + 1); }}
        />
      )}
    />
  );
};

export default PxkCongDoanPage;
